<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Sorting Algorithm Visualizer</title>
  <style>
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }

    body {
      background-color: #1a1a1a;
      color: #e0e0e0;
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      min-height: 100vh;
      padding: 20px;
    }

    .container {
      width: 100%;
      max-width: 1000px;
    }

    h1 {
      text-align: center;
      margin-bottom: 30px;
      font-size: 2em;
    }

    #bars {
      display: flex;
      align-items: flex-end;
      justify-content: center;
      gap: 2px;
      height: 400px;
      background-color: #0d0d0d;
      border: 1px solid #333;
      border-radius: 8px;
      padding: 20px;
      margin-bottom: 30px;
    }

    .bar {
      flex: 1;
      background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
      border-radius: 4px;
      transition: height 0.1s ease;
      box-shadow: 0 0 10px rgba(102, 126, 234, 0.3);
    }

    .bar.active {
      background: linear-gradient(135deg, #f093fb 0%, #f5576c 100%);
      box-shadow: 0 0 15px rgba(245, 87, 108, 0.8);
    }

    .bar.sorted {
      background: linear-gradient(135deg, #4ade80 0%, #22c55e 100%);
      box-shadow: 0 0 10px rgba(74, 222, 128, 0.3);
    }

    .controls {
      display: flex;
      gap: 15px;
      justify-content: center;
      flex-wrap: wrap;
    }

    button {
      padding: 12px 24px;
      font-size: 16px;
      font-weight: 600;
      border: none;
      border-radius: 6px;
      cursor: pointer;
      transition: all 0.2s ease;
      text-transform: uppercase;
      letter-spacing: 0.5px;
    }

    #sort {
      background-color: #667eea;
      color: white;
    }

    #sort:hover:not(:disabled) {
      background-color: #5568d3;
      transform: translateY(-2px);
      box-shadow: 0 5px 15px rgba(102, 126, 234, 0.4);
    }

    #shuffle {
      background-color: #f5576c;
      color: white;
    }

    #shuffle:hover:not(:disabled) {
      background-color: #e03d52;
      transform: translateY(-2px);
      box-shadow: 0 5px 15px rgba(245, 87, 108, 0.4);
    }

    #reset {
      background-color: #4ade80;
      color: white;
    }

    #reset:hover:not(:disabled) {
      background-color: #22c55e;
      transform: translateY(-2px);
      box-shadow: 0 5px 15px rgba(74, 222, 128, 0.4);
    }

    button:disabled {
      opacity: 0.6;
      cursor: not-allowed;
      transform: none;
    }
  </style>
</head>
<body>
  <div class="container">
    <h1>Sorting Algorithm Visualizer</h1>

    <div id="bars"></div>

    <div class="controls">
      <button id="shuffle">Shuffle</button>
      <button id="sort">Sort</button>
      <button id="reset">Reset</button>
    </div>
  </div>

  <script>
    class SortingVisualizer {
      constructor() {
        this.array = [];
        this.barsContainer = document.getElementById('bars');
        this.sortBtn = document.getElementById('sort');
        this.shuffleBtn = document.getElementById('shuffle');
        this.resetBtn = document.getElementById('reset');

        this.i = 0;
        this.j = 0;
        this.swapped = false;
        this.isSorting = false;

        this.init();
        this.setupEventListeners();
      }

      init() {
        this.array = Array.from({ length: 50 }, (_, i) => i + 1);
        this.shuffleArray();
      }

      setupEventListeners() {
        this.sortBtn.addEventListener('click', () => this.animateSort());
        this.shuffleBtn.addEventListener('click', () => this.handleShuffle());
        this.resetBtn.addEventListener('click', () => this.handleReset());
      }

      shuffleArray() {
        for (let i = this.array.length - 1; i > 0; i--) {
          const j = Math.floor(Math.random() * (i + 1));
          [this.array[i], this.array[j]] = [this.array[j], this.array[i]];
        }
        this.resetSortState();
      }

      resetSortState() {
        this.i = 0;
        this.j = 0;
        this.swapped = false;
        this.isSorting = false;
      }

      sorted() {
        for (let i = 0; i < this.array.length - 1; i++) {
          if (this.array[i] > this.array[i + 1]) {
            return false;
          }
        }
        return true;
      }

      sortStep() {
        if (this.sorted()) {
          return true;
        }

        if (this.j < this.array.length - 1 - this.i) {
          if (this.array[this.j] > this.array[this.j + 1]) {
            [this.array[this.j], this.array[this.j + 1]] = [this.array[this.j + 1], this.array[this.j]];
            this.swapped = true;
          }
          this.j++;
        } else {
          this.i++;
          this.j = 0;
          if (!this.swapped) {
            this.i = this.array.length;
          }
          this.swapped = false;
        }

        this.render();
        return this.sorted();
      }

      render() {
        const maxValue = Math.max(...this.array);
        this.barsContainer.innerHTML = '';

        this.array.forEach((value, index) => {
          const bar = document.createElement('div');
          bar.className = 'bar';

          if (this.sorted()) {
            bar.classList.add('sorted');
          } else if (index === this.j || index === this.j + 1) {
            bar.classList.add('active');
          }

          const heightPercent = (value / maxValue) * 100;
          bar.style.height = heightPercent + '%';
          this.barsContainer.appendChild(bar);
        });
      }

      animateSort() {
        if (this.isSorting || this.sorted()) return;

        this.isSorting = true;
        this.sortBtn.disabled = true;
        this.shuffleBtn.disabled = true;
        this.resetBtn.disabled = true;

        const interval = setInterval(() => {
          const done = this.sortStep();

          if (done) {
            clearInterval(interval);
            this.isSorting = false;
            this.sortBtn.disabled = false;
            this.shuffleBtn.disabled = false;
            this.resetBtn.disabled = false;
            this.render();
          }
        }, 20);
      }

      handleShuffle() {
        if (this.isSorting) return;
        this.shuffleArray();
        this.render();
      }

      handleReset() {
        if (this.isSorting) return;
        this.init();
        this.render();
      }

      setArray(a) {
        this.array = [...a];
        this.resetSortState();
        this.render();
      }

      getArray() {
        return [...this.array];
      }
    }

    const visualizer = new SortingVisualizer();
    visualizer.render();

    window.viz = {
      array: () => visualizer.getArray(),
      setArray: (a) => visualizer.setArray(a),
      sortStep: () => visualizer.sortStep(),
      sorted: () => visualizer.sorted(),
    };
  </script>
</body>
</html>
